import os
import subprocess
import json
import re
from google.cloud import storage
from pathlib import Path
import tempfile
import shlex

ALLOWED_FORMATS = {'jpg', 'jpeg', 'png', 'gif', 'webp', 'bmp', 'tiff', 'tif'}
ALLOWED_OPTIONS = {
    'resize', 'quality', 'format', 'rotate', 'crop', 'blur', 'sharpen',
    'brightness-contrast', 'normalize', 'grayscale', 'flip', 'flop'
}
MAX_FILE_SIZE = 50 * 1024 * 1024  # 50MB
MAX_DIMENSION = 10000

def validate_filename(filename):
    """Validate filename to prevent path traversal and command injection"""
    if not filename:
        raise ValueError("Filename cannot be empty")
    
    # Remove any path components
    filename = os.path.basename(filename)
    
    # Check for dangerous characters
    if re.search(r'[;&|`$<>\\]', filename):
        raise ValueError("Filename contains invalid characters")
    
    # Check for null bytes
    if '\x00' in filename:
        raise ValueError("Filename contains null bytes")
    
    return filename

def validate_format(format_str):
    """Validate output format"""
    if not format_str:
        return None
    
    format_str = format_str.lower().strip()
    if format_str not in ALLOWED_FORMATS:
        raise ValueError(f"Invalid format. Allowed formats: {ALLOWED_FORMATS}")
    
    return format_str

def validate_dimension(value, param_name):
    """Validate dimension values"""
    try:
        val = int(value)
        if val <= 0 or val > MAX_DIMENSION:
            raise ValueError(f"{param_name} must be between 1 and {MAX_DIMENSION}")
        return val
    except (ValueError, TypeError):
        raise ValueError(f"Invalid {param_name} value")

def validate_percentage(value, param_name):
    """Validate percentage values"""
    try:
        val = float(value)
        if val < 0 or val > 100:
            raise ValueError(f"{param_name} must be between 0 and 100")
        return val
    except (ValueError, TypeError):
        raise ValueError(f"Invalid {param_name} value")

def build_convert_command(input_path, output_path, options):
    """Build ImageMagick convert command with validated parameters"""
    cmd = ['convert']
    
    # Add resource limits to prevent DoS
    cmd.extend(['-limit', 'memory', '256MiB'])
    cmd.extend(['-limit', 'map', '512MiB'])
    cmd.extend(['-limit', 'disk', '1GiB'])
    cmd.extend(['-limit', 'time', '60'])
    
    # Input file
    cmd.append(input_path)
    
    # Process options in a specific order for security
    if 'resize' in options:
        resize = options['resize']
        # Validate resize format: WxH or W% or xH
        if re.match(r'^\d+x\d+[!<>^]?$', resize):
            cmd.extend(['-resize', resize])
        elif re.match(r'^\d+%$', resize):
            cmd.extend(['-resize', resize])
        elif re.match(r'^x\d+$', resize):
            cmd.extend(['-resize', resize])
        else:
            raise ValueError("Invalid resize format")
    
    if 'quality' in options:
        quality = validate_percentage(options['quality'], 'quality')
        cmd.extend(['-quality', str(int(quality))])
    
    if 'rotate' in options:
        rotate = options['rotate']
        if rotate not in ['90', '180', '270', '-90', '-180', '-270']:
            raise ValueError("Invalid rotation value")
        cmd.extend(['-rotate', rotate])
    
    if 'crop' in options:
        crop = options['crop']
        # Validate crop format: WxH+X+Y
        if not re.match(r'^\d+x\d+\+\d+\+\d+$', crop):
            raise ValueError("Invalid crop format")
        cmd.extend(['-crop', crop])
    
    if 'blur' in options:
        blur = options['blur']
        # Validate blur format: radiusxsigma
        if not re.match(r'^\d+(\.\d+)?x\d+(\.\d+)?$', blur):
            raise ValueError("Invalid blur format")
        cmd.extend(['-blur', blur])
    
    if 'sharpen' in options:
        sharpen = options['sharpen']
        # Validate sharpen format: radiusxsigma
        if not re.match(r'^\d+(\.\d+)?x\d+(\.\d+)?$', sharpen):
            raise ValueError("Invalid sharpen format")
        cmd.extend(['-sharpen', sharpen])
    
    if 'brightness-contrast' in options:
        bc = options['brightness-contrast']
        # Validate format: brightnessxcontrast
        if not re.match(r'^-?\d+x-?\d+$', bc):
            raise ValueError("Invalid brightness-contrast format")
        cmd.extend(['-brightness-contrast', bc])
    
    if options.get('normalize') == 'true':
        cmd.append('-normalize')
    
    if options.get('grayscale') == 'true':
        cmd.extend(['-colorspace', 'Gray'])
    
    if options.get('flip') == 'true':
        cmd.append('-flip')
    
    if options.get('flop') == 'true':
        cmd.append('-flop')
    
    # Strip metadata for privacy and size reduction
    cmd.append('-strip')
    
    # Output file
    cmd.append(output_path)
    
    return cmd

def parse_conversion_options(metadata):
    """Parse and validate conversion options from metadata"""
    if not metadata:
        return {}
    
    options = {}
    
    for key, value in metadata.items():
        # Only process conversion-related metadata
        if not key.startswith('convert_'):
            continue
        
        option_name = key.replace('convert_', '')
        
        if option_name not in ALLOWED_OPTIONS:
            continue
        
        # Sanitize value
        if not isinstance(value, str):
            value = str(value)
        
        # Remove any dangerous characters
        value = re.sub(r'[;&|`$<>\\]', '', value)
        
        if '\x00' in value:
            continue
        
        options[option_name] = value.strip()
    
    return options

def process_image(event, context):
    """Cloud Function triggered by Cloud Storage to convert images"""
    
    try:
        # Extract event data
        bucket_name = event['bucket']
        file_name = event['name']
        metadata = event.get('metadata', {})
        
        print(f"Processing file: {file_name} from bucket: {bucket_name}")
        
        # Validate filename
        safe_filename = validate_filename(file_name)
        
        # Parse conversion options
        options = parse_conversion_options(metadata)
        
        if not options:
            print("No conversion options found in metadata. Skipping.")
            return
        
        # Initialize storage client
        storage_client = storage.Client()
        source_bucket = storage_client.bucket(bucket_name)
        source_blob = source_bucket.blob(file_name)
        
        # Check file size
        blob_metadata = source_blob.metadata or {}
        if source_blob.size and source_blob.size > MAX_FILE_SIZE:
            raise ValueError(f"File size exceeds maximum allowed size of {MAX_FILE_SIZE} bytes")
        
        # Determine output format
        output_format = validate_format(options.get('format'))
        
        if output_format:
            base_name = os.path.splitext(safe_filename)[0]
            output_filename = f"{base_name}.{output_format}"
        else:
            output_filename = safe_filename
        
        # Create temporary directory
        with tempfile.TemporaryDirectory() as temp_dir:
            # Download source file
            input_path = os.path.join(temp_dir, 'input_file')
            output_path = os.path.join(temp_dir, 'output_file')
            
            print(f"Downloading {file_name}...")
            source_blob.download_to_filename(input_path)
            
            # Verify downloaded file size
            actual_size = os.path.getsize(input_path)
            if actual_size > MAX_FILE_SIZE:
                raise ValueError("Downloaded file exceeds size limit")
            
            # Build and execute convert command
            cmd = build_convert_command(input_path, output_path, options)
            
            print(f"Executing command: {' '.join(cmd)}")
            
            # Execute with timeout and security constraints
            result = subprocess.call(
                cmd,
                timeout=60,
                cwd=temp_dir,
                env={'PATH': '/usr/bin:/bin'}
            )
            
            if result != 0:
                raise RuntimeError(f"ImageMagick convert failed with exit code {result}")
            
            # Verify output file was created
            if not os.path.exists(output_path):
                raise RuntimeError("Output file was not created")
            
            # Verify output file size
            output_size = os.path.getsize(output_path)
            if output_size > MAX_FILE_SIZE:
                raise ValueError("Output file exceeds size limit")
            
            # Determine output bucket (use metadata or same bucket)
            output_bucket_name = metadata.get('output_bucket', bucket_name)
            output_bucket = storage_client.bucket(output_bucket_name)
            
            # Determine output path
            output_prefix = metadata.get('output_prefix', 'converted/')
            output_blob_name = f"{output_prefix}{output_filename}"
            
            # Upload converted file
            output_blob = output_bucket.blob(output_blob_name)
            
            print(f"Uploading to {output_bucket_name}/{output_blob_name}...")
            output_blob.upload_from_filename(output_path)
            
            # Set metadata on output file
            output_blob.metadata = {
                'source_file': file_name,
                'converted_at': context.timestamp,
                'conversion_options': json.dumps(options)
            }
            output_blob.patch()
            
            print(f"Successfully converted {file_name} to {output_blob_name}")
            
    except subprocess.TimeoutExpired:
        print("ERROR: ImageMagick conversion timed out")
        raise
    except Exception as e:
        print(f"ERROR: {str(e)}")
        raise

def main(event, context):
    """Entry point for Cloud Function"""
    return process_image(event, context)